using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set OPENAI_API_KEY (or OPENAI_BASE_URL for a compatible
// endpoint) before running.  Default model: gpt-4o-mini.
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new InvalidOperationException(
    "Set the OPENAI_API_KEY environment variable before running.");
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

// ---------------------------------------------------------------------------
// Build the underlying IChatClient from OpenAI
// ---------------------------------------------------------------------------
var clientOptions = new OpenAI.OpenAIClientOptions();
if (baseUrl is not null)
    clientOptions.Endpoint = new Uri(baseUrl);

var openAiClient = new OpenAIClient(new ApiKeyCredential(apiKey), clientOptions);

IChatClient chatClient = openAiClient.GetChatClient(model).AsIChatClient();

// ---------------------------------------------------------------------------
// Web-search provider – uses the TextSearchProvider from Microsoft.Agents.AI.
// The search delegate calls a simple free web-search API (DuckDuckGo instant
// answer / html endpoint) so no extra API key is required.
// ---------------------------------------------------------------------------
var searchProvider = new TextSearchProvider(
    searchAsync: async (query, ct) =>
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
        Console.ResetColor();

        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url, ct);

        // Extract result snippets from the HTML response
        var results = new List<TextSearchProvider.TextSearchResult>();
        var snippetTag = "class=\"result__snippet\">";
        var idx = 0;
        while (results.Count < 6 && (idx = html.IndexOf(snippetTag, idx, StringComparison.Ordinal)) >= 0)
        {
            idx += snippetTag.Length;
            var end = html.IndexOf('<', idx);
            if (end <= idx) continue;

            var snippet = System.Net.WebUtility.HtmlDecode(html[idx..end]).Trim();
            if (snippet.Length > 0)
            {
                results.Add(new TextSearchProvider.TextSearchResult
                {
                    SourceName = $"Web result {results.Count + 1}",
                    Text = snippet
                });
            }
        }

        if (results.Count == 0)
            results.Add(new TextSearchProvider.TextSearchResult
            {
                SourceName = "DuckDuckGo",
                Text = "No results found for this query."
            });

        return results.AsEnumerable();
    },
    options: new TextSearchProviderOptions
    {
        FunctionToolName        = "web_search",
        FunctionToolDescription = "Search the web for current information on a topic. Returns a list of relevant snippets.",
        SearchTime              = TextSearchProviderOptions.TextSearchBehavior.FunctionCall
    },
    loggerFactory: LoggerFactory.Create(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning))
);

// ---------------------------------------------------------------------------
// Note-taking provider – uses the TodoProvider to let the agent keep a
// structured list of findings as it researches.
// ---------------------------------------------------------------------------
var noteProvider = new TodoProvider(new TodoProviderOptions
{
    Instructions = """
        Use the to-do list as your research notebook.
        Add a new item for each key finding or fact you discover.
        When you finish researching, review your notes to write the summary.
        """
});

// ---------------------------------------------------------------------------
// Assemble the ChatClientAgent with both providers
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient: chatClient,
    options: new ChatClientAgentOptions
    {
        Name        = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes structured notes.",
        AIContextProviders = [searchProvider, noteProvider],
        ChatOptions = new ChatOptions { Temperature = 0.2f }
    },
    loggerFactory: LoggerFactory.Create(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning))
);

agent.Instructions = """
    You are a research assistant. When the user gives you a topic:
    1. Search the web multiple times with different queries to gather information.
    2. Record each key finding as a to-do / note item.
    3. After gathering enough information, write a clear, well-structured summary
       with the most important points, organized by theme.
    4. Cite which search results informed each section.
    Always be thorough – perform at least 3 different searches before summarizing.
    """;

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════════════════╗");
Console.WriteLine("║           🔬  Research Agent  (powered by AI)       ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.      ║");
Console.WriteLine("╚══════════════════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input) || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var response = await agent.RunAsync(input, session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("━━━ Research Summary ━━━");
        Console.ResetColor();

        foreach (var msg in response.Messages)
        {
            if (msg.Role == ChatRole.Assistant && msg.Text is { Length: > 0 })
                Console.WriteLine(msg.Text);
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

