using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set OPENAI_API_KEY (or OPENAI_BASE_URL for a compatible
// endpoint) before running.  Default model: gpt-4o-mini.
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new InvalidOperationException(
    "Set the OPENAI_API_KEY environment variable before running.");
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

// ---------------------------------------------------------------------------
// Build the underlying IChatClient from OpenAI
// ---------------------------------------------------------------------------
var clientOptions = new OpenAI.OpenAIClientOptions();
if (baseUrl is not null)
    clientOptions.Endpoint = new Uri(baseUrl);

var openAiClient = new OpenAIClient(new ApiKeyCredential(apiKey), clientOptions);

IChatClient chatClient = openAiClient.GetChatClient(model).AsIChatClient();

// ---------------------------------------------------------------------------
// Web-search provider – uses the TextSearchProvider from Microsoft.Agents.AI.
// The search delegate calls a simple free web-search API (DuckDuckGo instant
// answer / html endpoint) so no extra API key is required.
// ---------------------------------------------------------------------------
var searchProvider = new TextSearchProvider(
    searchAsync: async (query, ct) =>
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
        Console.ResetColor();

        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url, ct);

        // Extract result snippets from the HTML response
        var results = new List<TextSearchProvider.TextSearchResult>();
        var snippetTag = "class=\"result__snippet\">";
        var idx = 0;
        while (results.Count < 6 && (idx = html.IndexOf(snippetTag, idx, StringComparison.Ordinal)) >= 0)
        {
            idx += snippetTag.Length;
            var end = html.IndexOf('<', idx);
            if (end <= idx) continue;

            var snippet = System.Net.WebUtility.HtmlDecode(html[idx..end]).Trim();
            if (snippet.Length > 0)
            {
                results.Add(new TextSearchProvider.TextSearchResult
                {
                    SourceName = $"Web result {results.Count + 1}",
                    Text = snippet
                });
            }
        }

        if (results.Count == 0)
            results.Add(new TextSearchProvider.TextSearchResult
            {
                SourceName = "DuckDuckGo",
                Text = "No results found for this query."
            });

        return results.AsEnumerable();
    },
    options: new TextSearchProviderOptions
    {
        FunctionToolName        = "web_search",
        FunctionToolDescription = "Search the web for current information on a topic. Returns a list of relevant snippets.",
        SearchTime              = TextSearchProviderOptions.TextSearchBehavior.FunctionCall
    },
