// structured list of findings as it researches.
// ---------------------------------------------------------------------------
var noteProvider = new TodoProvider(new TodoProviderOptions
{
    Instructions = """
        Use the to-do list as your research notebook.
        Add a new item for each key finding or fact you discover.
        When you finish researching, review your notes to write the summary.
        """
});

// ---------------------------------------------------------------------------
// Assemble the ChatClientAgent with both providers
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient: chatClient,
    options: new ChatClientAgentOptions
    {
        Name        = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes structured notes.",
        AIContextProviders = [searchProvider, noteProvider],
