 // Assemble the ChatClientAgent with both providers
 // ---------------------------------------------------------------------------
 var instructions = """
     You are a research assistant. When the user gives you a topic:
     1. Search the web multiple times with different queries to gather information.
     2. Record each key finding as a to-do / note item.
     3. After gathering enough information, write a clear, well-structured summary
        with the most important points, organized by theme.
     4. Cite which search results informed each section.
     Always be thorough – perform at least 3 different searches before summarizing.
     """;

 var agent = new ChatClientAgent(
     chatClient: chatClient,
     options: new ChatClientAgentOptions
     {
         Name        = "ResearchAgent",
         Description = "An AI research assistant that searches the web and takes structured notes.",
         AIContextProviders = [searchProvider, noteProvider],
         ChatOptions = new ChatOptions { Temperature = 0.2f }
     },
     loggerFactory: loggerFactory
 );

 // Instructions are set via the simple constructor overload, so rebuild using that
 agent = new ChatClientAgent(
     chatClient: chatClient,
     instructions: instructions,
     name: "ResearchAgent",
     description: "An AI research assistant that searches the web and takes structured notes.",
     tools: null,
     loggerFactory: loggerFactory
 ).AsBuilder()
  .UseAIContextProviders(searchProvider, noteProvider)
  .Build() is ChatClientAgent built ? built : agent;

 // ---------------------------------------------------------------------------
 // Interactive loop
 // ---------------------------------------------------------------------------
 Console.WriteLine("╔══════════════════════════════════════════════════════╗");
 Console.WriteLine("║           🔬  Research Agent  (powered by AI)       ║");
 Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.      ║");
 Console.WriteLine("╚══════════════════════════════════════════════════════╝");
 Console.WriteLine();

 var session = await agent.CreateSessionAsync();

 while (true)
 {
     Console.ForegroundColor = ConsoleColor.Cyan;
     Console.Write("Research topic> ");
     Console.ResetColor();

     var input = Console.ReadLine();
     if (string.IsNullOrWhiteSpace(input) || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     Console.WriteLine();
     Console.ForegroundColor = ConsoleColor.DarkGray;
     Console.WriteLine("Researching… (the agent will search the web and take notes)");
     Console.ResetColor();
     Console.WriteLine();

     try
     {
         var response = await agent.RunAsync(input, session);

         Console.ForegroundColor = ConsoleColor.Green;
         Console.WriteLine("━━━ Research Summary ━━━");
         Console.ResetColor();

         foreach (var msg in response.Messages)
         {
             if (msg.Role == ChatRole.Assistant && msg.Text is { Length: > 0 })
                 Console.WriteLine(msg.Text);
         }

         Console.WriteLine();
     }
     catch (Exception ex)
     {
         Console.ForegroundColor = ConsoleColor.Red;
         Console.WriteLine($"Error: {ex.Message}");
         Console.ResetColor();
         Console.WriteLine();
     }
 }

